import sys

def solve():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    P = list(map(int, data[1:N+1]))

    ranks = [0] * N
    used = [False] * N
    r = 1

    while True:
        max_score = -1
        count = 0
        for i in range(N):
            if not used[i] and P[i] > max_score:
                max_score = P[i]
                count = 1
            elif not used[i] and P[i] == max_score:
                count += 1

        if count == 0:
            break

        for i in range(N):
            if not used[i] and P[i] == max_score:
                ranks[i] = r
                used[i] = True

        r += count

    for rank in ranks:
        print(rank)

if __name__ == "__main__":
    solve()
